const d = items[0].json;
const c = d.counts || {};
const events = Array.isArray(d.events) ? d.events : [];

// === CONFIG ===
const LOGO_URL = 'https://ygri.interasia.com.co/assets/logo-short-BP0qi55G.png';
const TIMEZONE_LABEL = 'Asia/Shanghai';

// ===== Telegram MarkdownV2 (unchanged) =====
const esc = (s='') => String(s).replace(/([_*\[\]()~`>#+\-=|{}.!\\])/g, '\\$1');
const s = (n, w) => (n === 1 ? w : w + 's');

const tLines = [];
tLines.push(`*Good morning\\!* This is your daily summary for *Ygri CRM* — ${esc(d.date)} \\(${esc(TIMEZONE_LABEL)}\\)`);
tLines.push('');
tLines.push(`*Highlights*`);
tLines.push(`• ${esc(c.projects_created ?? 0)} new ${esc(s(c.projects_created ?? 0, 'project'))}`);
tLines.push(`• ${esc(c.comments_count ?? 0)} ${esc(s(c.comments_count ?? 0, 'comment'))}`);
tLines.push(`• ${esc(c.stage_changes ?? 0)} ${esc(s(c.stage_changes ?? 0, 'stage change'))}`);
if (events.length) {
  tLines.push('');
  tLines.push(`*Recent activity*`);
  for (const e of events.slice(0, 10)) {
    const icon =
      e.event_type === 'project_created' ? '🆕' :
      e.event_type === 'new_comment'    ? '💬' :
      e.event_type === 'stage_changed'  ? '🔁' : '•';
    const who   = e.actor ? ` \\(${esc(e.actor)}\\)` : '';
    const client= e.client_name ? ` — ${esc(e.client_name)}` : '';
    const stage = e.event_type === 'stage_changed'
      ? ` — ${esc(e.from_stage || '—')} → ${esc(e.to_stage || '—')}`
      : '';
    tLines.push(`  ${icon} ${esc(e.track_name)}${client}${stage}${who}`);
  }
} else {
  tLines.push('');
  tLines.push(`No activity recorded for this day.`);
}
tLines.push('');
tLines.push(`Have a great day\\! — *Ygri CRM*`);
const text = tLines.join('\n');

// ===== Plain text (email fallback) =====
const pLines = [];
pLines.push(`Good morning! This is your daily summary for Ygri CRM — ${d.date} (${TIMEZONE_LABEL}).`);
pLines.push('');
pLines.push(`Highlights: ${c.projects_created ?? 0} ${s(c.projects_created ?? 0,'project')}, `
  + `${c.comments_count ?? 0} ${s(c.comments_count ?? 0,'comment')}, `
  + `${c.stage_changes ?? 0} ${s(c.stage_changes ?? 0,'stage change')}.`);
if (events.length) {
  pLines.push('');
  pLines.push('Recent activity:');
  for (const e of events.slice(0, 10)) {
    const icon =
      e.event_type === 'project_created' ? '🆕' :
      e.event_type === 'new_comment'    ? '💬' :
      e.event_type === 'stage_changed'  ? '🔁' : '•';
    const who = e.actor ? ` (${e.actor})` : '';
    const client = e.client_name ? ` — ${e.client_name}` : '';
    const stage = e.event_type === 'stage_changed'
      ? ` — ${e.from_stage || '—'} → ${e.to_stage || '—'}`
      : '';
    pLines.push(`  ${icon} ${e.track_name}${client}${stage}${who}`);
  }
}
pLines.push('');
pLines.push('Have a great day! — Ygri CRM');
const text_plain = pLines.join('\n');

// ===== HTML (styled, with logo) =====
const hEsc = (s='') => String(s).replace(/[&<>"]/g, ch =>
  ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[ch]));
const pill = (label, value) =>
  `<div class="pill"><span>${hEsc(label)}</span><b>${hEsc(value)}</b></div>`;
const eventsHtml = events.slice(0,10).map(e=>{
  const icon =
    e.event_type === 'project_created' ? '🆕' :
    e.event_type === 'new_comment'    ? '💬' :
    e.event_type === 'stage_changed'  ? '🔁' : '•';
  const who = e.actor ? ` <span class="muted">(${hEsc(e.actor)})</span>` : '';
  const client = e.client_name ? ` — ${hEsc(e.client_name)}` : '';
  const stage = e.event_type === 'stage_changed'
    ? ` — <span class="stage">${hEsc(e.from_stage || '—')} → ${hEsc(e.to_stage || '—')}</span>`
    : '';
  return `<div class="event">${icon} ${hEsc(e.track_name)}${client}${stage}${who}</div>`;
}).join('');

const html = `
<!doctype html>
<meta charset="utf-8">
<style>
  body{background:#f6f7fb;margin:0;padding:24px;font:14px/1.5 system-ui,-apple-system,Segoe UI,Roboto,Arial;}
  .card{max-width:720px;margin:0 auto;background:#fff;border-radius:16px;padding:24px;box-shadow:0 8px 28px rgba(0,0,0,.08)}
  .logo{display:flex;justify-content:center;margin:4px 0 12px}
  .logo img{width:48px;height:48px;border-radius:10px;display:block}
  h1{margin:0 0 6px;font-size:18px}
  .subtitle{color:#667;margin:2px 0 16px}
  .row{display:flex;gap:8px;flex-wrap:wrap;margin:12px 0 18px}
  .pill{background:#f1f4f8;border-radius:999px;padding:8px 12px;display:inline-flex;gap:8px}
  .pill span{color:#667}
  .pill b{font-weight:700}
  .section-title{margin:12px 0 8px;font-weight:600}
  .event{padding:10px 0;border-top:1px solid #eee}
  .muted{color:#667}
  .stage{font-weight:600}
  .footer{margin-top:18px;color:#889;font-size:12px}
  @media (prefers-color-scheme: dark) {
    body{background:#0b0e14}
    .card{background:#111827;color:#e5e7eb}
    .pill{background:#1f2937}
    .muted{color:#a1a1aa}
    .event{border-top-color:#222}
  }
</style>
<body>
  <div class="card">
    <div class="logo">
      <img src="${LOGO_URL}" alt="Ygri CRM logo" width="48" height="48" />
    </div>
    <h1>Daily summary for Ygri CRM</h1>
    <div class="subtitle">${hEsc(d.date)} · ${hEsc(TIMEZONE_LABEL)}</div>
    <div class="row">
      ${pill('Projects', c.projects_created ?? 0)}
      ${pill('Comments', c.comments_count ?? 0)}
      ${pill('Stage changes', c.stage_changes ?? 0)}
    </div>
    ${events.length ? `<div class="section-title">Recent activity</div>${eventsHtml}` : `<div class="section-title">Recent activity</div><div class="muted">No activity recorded for this day.</div>`}
    <div class="footer">Have a great day! — Ygri CRM</div>
  </div>
</body>
`;

const subject = `Daily summary • ${d.date} (${TIMEZONE_LABEL})`;

return [{ json: { text, text_plain, html, subject } }];
